const item = $input.first();
const body = item.json.body || item.json;
const binary = item.binary || {};

const hasBinary = binary && binary.prescription_image;

if (!hasBinary) {
  return [{ json: {
    success: false,
    error: 'No prescription image found. Please attach an image.',
    user_id: body.user_id || '',
    patient_token: body.patient_token || '',
    has_image: false
  }}];
}

const img = binary.prescription_image;

// Use getBinaryDataBuffer to correctly read binary data
// in BOTH filesystem and memory binary modes (fixes 'Cannot decode filesystem-v2' error)
const buffer = await this.helpers.getBinaryDataBuffer(0, 'prescription_image');
const base64 = buffer.toString('base64');

return [{
  json: {
    user_id: body.user_id || '',
    patient_token: body.patient_token || '',
    has_image: true,
    image_base64: base64,
    image_mime_type: img.mimeType || 'image/jpeg',
    image_file_name: img.fileName || 'prescription.jpg'
  },
  binary: { prescription_image: img }
}];

