const ocrData = $input.first().json;
const prevData = $('Extract Image Data').first().json;

const pages = ocrData.pages || [];
const ocrText = pages.length > 0 ? (pages[0].markdown || '') : '';
const lower = ocrText.toLowerCase();

const rxKeywords = [
  'prescription', 'rx', 'medication', 'dosage', 'mg', 'ml',
  'tablet', 'capsule', 'doctor', 'dr.', 'patient', 'diagnosis',
  'clinic', 'hospital', 'pharmacist', 'dispense', 'refill',
  'twice daily', 'once daily', 'take with', 'after meals',
  'before meals', 'amoxicillin', 'metformin', 'paracetamol',
  'ibuprofen', 'injection', 'syrup', 'sig:', 'disp:'
];

const matchCount = rxKeywords.filter(kw => lower.includes(kw)).length;
const isPrescription = matchCount >= 2;

return [{ json: {
  user_id: prevData.user_id,
  patient_token: prevData.patient_token,
  has_image: true,
  raw_ocr_text: ocrText,
  is_prescription: isPrescription,
  keyword_match_count: matchCount
}}];

const rawText = $json.raw_ocr_text || '';

function extractAfter(text, keywords) {
  for (const kw of keywords) {
    const idx = text.toLowerCase().indexOf(kw.toLowerCase());
    if (idx !== -1) {
      const rest = text.substring(idx + kw.length).replace(/^[:\s]+/, '').trim();
      const firstLine = rest.split('\n')[0].trim();
      if (firstLine.length > 0 && firstLine.length < 120) return firstLine;
    }
  }
  return null;
}

const parsed = {
  is_valid_prescription: true,
  doctor_name: extractAfter(rawText, ['Doctor:', 'Dr.', 'Prescriber:', 'Physician:']),
  doctor_specialty: extractAfter(rawText, ['Specialty:', 'Department:', 'Dept:']),
  clinic_name: extractAfter(rawText, ['Clinic:', 'Hospital:', 'Health Center:', 'Facility:']),
  patient_name: extractAfter(rawText, ['Patient:', 'Patient Name:', 'Name:']),
  date: extractAfter(rawText, ['Date:', 'Prescribed on:', 'Written:']),
  diagnosis: extractAfter(rawText, ['Diagnosis:', 'Dx:', 'Impression:', 'Condition:']),
  refills: extractAfter(rawText, ['Refills:', 'Refill:']),
  raw_ocr_text: rawText
};

return [{ json: {
  user_id: $json.user_id,
  patient_token: $json.patient_token,
  parsed_prescription: parsed,
  raw_ocr_text: rawText
}}];

const aiResponse = $input.first().json;
const parseResult = $('Parse Prescription').first().json;

// Real Gemini output path confirmed from pinned data:
// aiResponse.content.parts[0].text contains the JSON string
const messageContent =
  aiResponse?.content?.parts?.[0]?.text ||
  aiResponse?.output ||
  aiResponse?.text ||
  '{"medicines":[]}';

// Parse the JSON response from the AI
let medicines = [];
try {
  // Clean up potential markdown code fences the model might add
  const cleaned = messageContent.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();
  const parsed = JSON.parse(cleaned);
  medicines = Array.isArray(parsed.medicines) ? parsed.medicines : [];
} catch (e) {
  // Fallback: extract quoted strings as medicine names
  const matches = messageContent.match(/"([^"]+)"/g);
  if (matches) {
    medicines = matches.map(m => m.replace(/"/g, '').trim()).filter(Boolean);
  }
}

const parsed = parseResult.parsed_prescription;

return [{ json: {
  success: true,
  user_id: parseResult.user_id,
  patient_token: parseResult.patient_token,
  parsed_prescription: {
    is_valid_prescription: parsed.is_valid_prescription,
    doctor_name: parsed.doctor_name,
    doctor_specialty: parsed.doctor_specialty,
    clinic_name: parsed.clinic_name,
    patient_name: parsed.patient_name,
    date: parsed.date,
    diagnosis: parsed.diagnosis,
    refills: parsed.refills
  },
  medicines: medicines,
  medicine_count: medicines.length
}}];

const data = $input.first().json;
return [{ json: {
  success: false,
  error: data.error || 'No prescription image was provided.',
  hint: 'Send a POST request with a file field named prescription_image plus user_id and patient_token.',
  user_id: data.user_id || ''
}}];
